const allInput = $input.all();
const result = [];
// Loop over input items and add a new field called 'myNewField' to the JSON of each one
for (const item of allInput) {
  const {id, startedAt, stoppedAt, status, errorType, errorMessage} = item.json
  const startTime = DateTime.fromISO(startedAt);
  const stopTime = DateTime.fromISO(stoppedAt);

  const durationSecs = stopTime.diff(startTime, "seconds").seconds;

  result.push(
    {
      json:{
        "executionId": id,  
        durationSecs,
        status,
        errorType,
        errorMessage 
      }
    }       
  );
}

return result;

